165	func sanitizeEndpointName(s string) string {
166		s = strings.ToLower(strings.TrimSpace(s))
167		var b strings.Builder
168		lastDash := false
169		for _, r := range s {
170			keep := unicode.IsLetter(r) || unicode.IsDigit(r)
171			if keep {
172				b.WriteRune(r)
173				lastDash = false
174				continue
175			}
176			if !lastDash {
177				b.WriteByte('-')
178				lastDash = true
179			}
180		}
181		out := strings.Trim(b.String(), "-")
182		if out == "" {
183			return "endpoint"
184		}
185		return out
186	}
